// In the handleConnect function in App.js, ensure it's using proper handle IDs
// Already in your App.js:
const handleConnect = useCallback(
  (params) => {
    const newEdge = {
      id: params.id || `e${params.source}-${params.target}-${Date.now()}`,
      source: params.source,
      target: params.target,
      sourceHandle: params.sourceHandle, // Make sure these are included
      targetHandle: params.targetHandle,
      ...params,
    };
    setEdges((eds) => [...eds, newEdge]);
  },
  [setEdges]
);
